import {
  MapContainer,
  TileLayer,
  Polyline,
  useMap,
} from "react-leaflet";
import { useState, useEffect } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

function FixMap() {
  const map = useMap();
  setTimeout(() => map.invalidateSize(), 100);
  return null;
}

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [position, setPosition] = useState([20, 77]);
  const [flightData, setFlightData] = useState(null);
  const [trail, setTrail] = useState([]);
  const [loading, setLoading] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);

  const fetchFlight = async () => {
    try {
      setLoading(true);
      setHasSearched(true);

      const res = await fetch(
        `http://localhost:5000/api/flights/${flightNo}`
      );
      const data = await res.json();

      if (data.error) {
        setFlightData(null);
        return;
      }

      const { latitude, longitude } = data;

      if (!latitude || !longitude || isNaN(latitude) || isNaN(longitude)) {
        setFlightData(null);
        return;
      }

      // ✨ Smooth movement
      setPosition((prev) => [
        prev[0] + (latitude - prev[0]) * 0.25,
        prev[1] + (longitude - prev[1]) * 0.25,
      ]);

      setFlightData(data);

      // ✈️ Limit trail (performance)
      setTrail((prev) => {
        const updated = [...prev, [latitude, longitude]];
        return updated.slice(-25);
      });
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // 🔄 Auto refresh
  useEffect(() => {
    if (!flightData) return;
    const interval = setInterval(fetchFlight, 4000);
    return () => clearInterval(interval);
  }, [flightData]);

  return (
    <div className="dashboard">
      {/* 🔴 PANEL */}
      <div className="panel">
        <h1 className="title">✈️ Flight Tracker</h1>

        <input
          value={flightNo}
          onChange={(e) => setFlightNo(e.target.value)}
          placeholder="Search (AIC, QTR, UAE...)"
        />

        <button onClick={fetchFlight}>
          {loading ? "Tracking..." : "Track Flight"}
        </button>

        {/* 🧠 Empty state */}
        {!flightData && !loading && hasSearched && (
          <div className="empty">
            <p>⚠️ No live tracking</p>
            <span>Try: AIC • QTR • UAE • BAW</span>
          </div>
        )}

        {!hasSearched && (
          <div className="empty">
            <p>🔍 Search for a flight</p>
            <span>Example: QTR, AIC, UAE</span>
          </div>
        )}

        {/* 📊 Flight Data */}
        {flightData && (
          <div className="card">
            <h2>{flightData.callsign}</h2>
            <p>{flightData.country}</p>

            <div className="stats">
              <div>
                <span>Altitude</span>
                <b>{Math.round(flightData.altitude)}</b>
              </div>
              <div>
                <span>Speed</span>
                <b>{Math.round(flightData.velocity)}</b>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* 🌍 MAP */}
      <MapContainer
        center={position}
        zoom={5}
        className="map"
        key={position.toString()}
      >
        <FixMap />

        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} flightData={flightData} />

        {trail.length > 1 && (
          <Polyline
            positions={trail}
            pathOptions={{
              color: "#ff2a2a",
              weight: 4,
              opacity: 0.9,
            }}
          />
        )}
      </MapContainer>
    </div>
  );
}
